function solve(n, edges, k) {
    let maxW = 0;
    for (let e of edges) {
        if (e[2] > maxW) maxW = e[2];
    }

    let low = 0, high = maxW;
    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (isValid(n, edges, k, mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

function isValid(n, edges, k, X) {
    let parent = Array(n).fill().map((_, i) => i);
    let rank = Array(n).fill(1);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        let rootU = find(u);
        let rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootU]++;
                }
            }
        }
    }

    for (let [u, v, w] of edges) {
        if (w <= X) {
            union(u, v);
        }
    }

    let roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }
    return roots.size <= k;
}

