def solve(n: int, edges: list[list[int]], k: int) -> int:
    def is_valid(X):
        parent = list(range(n))
        rank = [1] * n

        def find(u):
            root = u
            while parent[root] != root:
                root = parent[root]
            while u != root:
                next_parent = parent[u]
                parent[u] = root
                u = next_parent
            return root

        for u, v, w in edges:
            if w <= X:
                root_u = find(u)
                root_v = find(v)
                if root_u != root_v:
                    if rank[root_u] < rank[root_v]:
                        parent[root_u] = root_v
                    else:
                        parent[root_v] = root_u
                        if rank[root_u] == rank[root_v]:
                            rank[root_u] += 1
        roots = set()
        for i in range(n):
            roots.add(find(i))
        return len(roots) <= k

    maxW = max(e[2] for e in edges) if edges else 0
    low, high = 0, maxW
    while low < high:
        mid = (low + high) // 2
        if is_valid(mid):
            high = mid
        else:
            low = mid + 1
    return low
```

