        let rootU = find(u);
        let rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootU]++;
                }
            }
        }
    }

    for (let [u, v, w] of edges) {
        if (w <= X) {
            union(u, v);
        }
    }

    let roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }
    return roots.size <= k;
}
